  1→import { useSources } from "@/features/sources/context/SourcesContext";
  2→import type { SourceId } from "@/lib/types/primitives";
  3→import { LiquidGlassInput, LiquidGlassSelect } from "@/modules/liquid-glass";
  4→import { useTranslation } from "@/platform/i18n/useTranslation";
  5→import { getGlassInputColors } from "@/platform/theme/glassStyles";
  6→import { useTheme, type Theme } from "@/platform/theme/useTheme";
  7→import { Picker } from "@react-native-picker/picker";
  8→import {
  9→  forwardRef,
 10→  useCallback,
 11→  useEffect,
 12→  useImperativeHandle,
 13→  useState,
 14→  type JSX,
 15→} from "react";
 16→import {
 17→  Modal,
 18→  Platform,
 19→  Pressable,
 20→  StyleSheet,
 21→  Text,
 22→  View,
 23→} from "react-native";
 24→
 25→const ADD_NEW_VALUE = "__ADD_NEW__";
 26→
 27→export interface SourceSelectorRef {
 28→  confirmNewSource: () => Promise<SourceId | undefined>;
 29→  cancelEdit: () => boolean;
 30→}
 31→
 32→export const SourceSelector = forwardRef<
 33→  SourceSelectorRef,
 34→  {
 35→    value: SourceId;
 36→    onValueChange: (sourceId: SourceId, isAutomatic?: boolean) => void;
 37→    onInteraction?: () => void;
 38→    onEditingChange?: (editing: boolean) => void;
 39→    onHasNoSourcesChange?: (hasNoSources: boolean) => void;
 40→  }
 41→>(function SourceSelector(
 42→  { value, onValueChange, onInteraction, onEditingChange, onHasNoSourcesChange },
 43→  ref
 44→): JSX.Element {
 45→  const { t } = useTranslation();
 46→  const theme = useTheme();
 47→  const { sources, createSource, getLastUsed } = useSources();
 48→
 49→  const [isEditingNewSource, setIsEditingNewSource] = useState(false);
 50→  const [pickerModalVisible, setPickerModalVisible] = useState(false);
 51→  const [newSourceText, setNewSourceText] = useState("");
 52→  const [tempValue, setTempValue] = useState(value);
 53→
 54→  const hasNoSources = sources.length === 0;
 55→
 56→  useEffect(() => {
 57→    onHasNoSourcesChange?.(hasNoSources);
 58→  }, [hasNoSources, onHasNoSourcesChange]);
 59→
 60→  useEffect(() => {
 61→    if (!value) {
 62→      const lastUsed = getLastUsed();
 63→      if (lastUsed) {
 64→        onValueChange(lastUsed.id, true);
 65→      }
 66→    }
 67→  }, [getLastUsed, value, onValueChange]);
 68→
 69→  // Sync tempValue when value changes externally
 70→  useEffect(() => {
 71→    setTempValue(value);
 72→  }, [value]);
 73→
 74→  const selectedSourceName = sources.find((s) => s.id === value)?.name ?? "";
 75→
 76→  const openPickerModal = useCallback(() => {
 77→    setTempValue(value || (sources.length > 0 ? sources[0].id : ""));
 78→    setPickerModalVisible(true);
 79→    onInteraction?.();
 80→  }, [value, sources, onInteraction]);
 81→
 82→  const handlePickerDone = useCallback(() => {
 83→    setPickerModalVisible(false);
 84→    if (tempValue === ADD_NEW_VALUE) {
 85→      setIsEditingNewSource(true);
 86→    } else if (tempValue) {
 87→      onValueChange(tempValue, false);
 88→    }
 89→  }, [tempValue, onValueChange]);
 90→
 91→  const handlePickerCancel = useCallback(() => {
 92→    setPickerModalVisible(false);
 93→    setTempValue(value);
 94→  }, [value]);
 95→
 96→  const handleConfirmNewSource = useCallback(async (): Promise<
 97→    SourceId | undefined
 98→  > => {
 99→    const trimmedSource = newSourceText.trim();
100→    if (!trimmedSource) {
101→      return undefined;
102→    }
103→
104→    const newSource = await createSource(trimmedSource);
105→    onValueChange(newSource.id, false);
106→    setIsEditingNewSource(false);
107→    setNewSourceText("");
108→    return newSource.id;
109→  }, [newSourceText, createSource, onValueChange]);
110→
111→  const handleCancelEdit = useCallback<() => boolean>((): boolean => {
112→    const wasEditing = isEditingNewSource;
113→    if (wasEditing) {
114→      setIsEditingNewSource(false);
115→    }
116→    setNewSourceText("");
117→    return wasEditing;
118→  }, [isEditingNewSource]);
119→
120→  useEffect(() => {
121→    onEditingChange?.(isEditingNewSource || hasNoSources);
122→  }, [isEditingNewSource, hasNoSources, onEditingChange]);
123→
124→  useImperativeHandle(
125→    ref,
126→    () => ({
127→      confirmNewSource: handleConfirmNewSource,
128→      cancelEdit: handleCancelEdit,
129→    }),
130→    [handleConfirmNewSource, handleCancelEdit]
131→  );
132→
133→  const handleWebPickerChange = useCallback(
134→    (itemValue: string) => {
135→      if (itemValue === ADD_NEW_VALUE) {
136→        setIsEditingNewSource(true);
137→        onInteraction?.();
138→      } else if (itemValue) {
139→        onValueChange(itemValue, false);
140→        onInteraction?.();
141→      }
142→    },
143→    [onValueChange, onInteraction]
144→  );
145→
146→  const isWeb = Platform.OS === "web";
147→  const themeColors = getThemeColors(theme);
148→
149→  return (
150→    <>
151→      <View style={styles.container}>
152→        {isWeb ? (
153→          <Picker
154→            selectedValue={value || ""}
155→            onValueChange={handleWebPickerChange}
156→            style={[styles.triggerButton, themeColors.triggerButton]}
157→          >
158→            {!value && (
159→              <Picker.Item
160→                label={t("sourceSelector.placeholder")}
161→                value=""
162→                enabled={false}
163→              />
164→            )}
165→            {sources.map((source) => (
166→              <Picker.Item
167→                key={source.id}
168→                label={source.name}
169→                value={source.id}
170→              />
171→            ))}
172→            <Picker.Item
173→              label={t("sourceSelector.addNew")}
174→              value={ADD_NEW_VALUE}
175→            />
176→          </Picker>
177→        ) : hasNoSources || isEditingNewSource ? (
178→          <LiquidGlassInput
179→            value={newSourceText}
180→            onChangeText={setNewSourceText}
181→            placeholder={t("sourceSelector.addNewPlaceholder")}
182→            variant="text"
183→            autoFocus
184→            maxLength={100}
185→            returnKeyType="done"
186→            onSubmitEditing={handleConfirmNewSource}
187→            style={styles.glassSelect}
188→          />
189→        ) : (
190→          <LiquidGlassSelect
191→            value={selectedSourceName}
192→            placeholder={t("sourceSelector.placeholder")}
193→            onPress={openPickerModal}
194→            style={styles.glassSelect}
195→          />
196→        )}
197→      </View>
198→
199→      {/* Picker Modal - shows full-height native iOS picker wheel */}
200→      <Modal
201→        visible={pickerModalVisible}
202→        transparent
203→        animationType="slide"
204→        onRequestClose={handlePickerCancel}
205→      >
206→        <View style={styles.pickerModalOverlay}>
207→          <Pressable
208→            style={styles.pickerModalBackdrop}
209→            onPress={handlePickerCancel}
210→          />
211→          <View
212→            style={[
213→              styles.pickerModalContent,
214→              {
215→                backgroundColor:
216→                  theme === "dark"
217→                    ? "rgba(44, 44, 46, 1)"
218→                    : "rgba(255, 255, 255, 1)",
219→              },
220→            ]}
221→          >
222→            <View style={styles.pickerToolbar}>
223→              <Pressable onPress={handlePickerCancel}>
224→                <Text style={styles.pickerToolbarButton}>
225→                  {t("recipeForm.discardChanges.cancel")}
226→                </Text>
227→              </Pressable>
228→              <Pressable onPress={handlePickerDone}>
229→                <Text
230→                  style={[
231→                    styles.pickerToolbarButton,
232→                    styles.pickerToolbarButtonDone,
233→                  ]}
234→                >
235→                  {t("recipeForm.submit")}
236→                </Text>
237→              </Pressable>
238→            </View>
239→            <Picker
240→              selectedValue={tempValue}
241→              onValueChange={setTempValue}
242→              style={styles.pickerWheel}
243→              itemStyle={themeColors.pickerItem}
244→            >
245→              {sources.map((source) => (
246→                <Picker.Item
247→                  key={source.id}
248→                  label={source.name}
249→                  value={source.id}
250→                />
251→              ))}
252→              <Picker.Item
253→                label={t("sourceSelector.addNew")}
254→                value={ADD_NEW_VALUE}
255→              />
256→            </Picker>
257→          </View>
258→        </View>
259→      </Modal>
260→    </>
261→  );
262→});
263→
264→function getThemeColors(theme: Theme) {
265→  const isDark = theme === "dark";
266→  const inputColors = getGlassInputColors(theme);
267→
268→  return {
269→    label: inputColors.label,
270→    text: inputColors.text,
271→    input: {
272→      backgroundColor: "transparent",
273→      borderColor: isDark ? "rgba(255, 255, 255, 0.2)" : "rgba(0, 0, 0, 0.1)",
274→      color: isDark ? "rgba(255, 255, 255, 0.5)" : "#000000",
