279→        : "rgba(0, 0, 0, 0.05)",
280→      borderColor: isDark ? "rgba(255, 255, 255, 0.2)" : "rgba(0, 0, 0, 0.1)",
281→    },
282→    pickerItem: {
283→      color: isDark ? "#FFFFFF" : "#000000",
284→      fontSize: 20,
285→    },
286→    placeholder: inputColors.placeholder,
287→  };
288→}
